INSERT INTO email_templates (slug, nome, assunto, html_content, variaveis, ativo)
VALUES (
  'trial-expirado-winback',
  'Trial Expirado - Regresso',
  'Volte ao Obra Sys com condições especiais',
  '<!DOCTYPE html><html lang="pt"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f4f4f5;font-family:Arial,Helvetica,sans-serif;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background-color:#f4f4f5;padding:40px 0;"><tr><td align="center"><table role="presentation" width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06);"><tr><td style="background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%); padding:32px 40px; text-align:center;"><img src="{{logoUrl}}" alt="Obra Sys" height="36" style="height:36px;" /></td></tr><tr><td style="padding:40px;"><p style="font-size:16px;color:#1a1a2e;line-height:1.6;margin:0 0 20px;">Olá,</p><p style="font-size:15px;color:#374151;line-height:1.7;margin:0 0 16px;">O seu trial no <strong>Obra Sys</strong> terminou, mas quisemos dar-lhe uma nova oportunidade para voltar.</p><p style="font-size:15px;color:#374151;line-height:1.7;margin:0 0 16px;">Sabemos que nem sempre é possível explorar tudo no momento certo. O dia a dia da obra exige muito, e muitas vezes aquilo que podia trazer mais organização acaba por ficar para depois.</p><p style="font-size:15px;color:#374151;line-height:1.7;margin:0 0 24px;">Por isso, criámos uma <strong>condição especial de regresso</strong>:</p><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin:0 0 24px;"><tr><td style="background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);border-radius:10px;padding:24px;text-align:center;"><p style="font-size:28px;font-weight:bold;color:#ffffff;margin:0 0 4px;">31,90€/mês</p><p style="font-size:14px;color:#fef3c7;margin:0;">durante 3 meses</p></td></tr></table><p style="font-size:15px;color:#374151;line-height:1.7;margin:0 0 16px;">Uma oportunidade para voltar a usar o Obra Sys com mais calma, recuperar o controlo dos seus processos, organizar obras, equipas e orçamentos, e sentir na prática o valor da plataforma no seu trabalho.</p><p style="font-size:14px;color:#6b7280;line-height:1.6;margin:0 0 28px;font-style:italic;">A oferta é exclusiva para antigos utilizadores em trial e estará disponível apenas por poucos dias.</p><table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td align="center"><a href="{{appUrl}}/auth" style="display:inline-block;background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);color:#ffffff;font-size:16px;font-weight:bold;text-decoration:none;padding:14px 40px;border-radius:8px;">Quero regressar</a></td></tr></table><p style="font-size:15px;color:#374151;line-height:1.7;margin:28px 0 0;">Se quiser regressar, teremos todo o gosto em recebê-lo de volta.</p><p style="font-size:15px;color:#374151;line-height:1.7;margin:20px 0 0;">Cumprimentos,<br/><strong>Equipa Obra Sys</strong></p></td></tr><tr><td style="background-color:#f9fafb;padding:24px 40px;text-align:center;border-top:1px solid #e5e7eb;"><p style="font-size:12px;color:#9ca3af;margin:0;">© {{ano}} Obra Sys. Todos os direitos reservados.</p></td></tr></table></td></tr></table></body></html>',
  '["{{logoUrl}}", "{{appUrl}}", "{{ano}}"]'::jsonb,
  true
);